// 1) Read input parameters from action args
const prefix = String(args.prefix ?? "").trim();
const name = String(args.name ?? "").trim();
const index = Number(args.index ?? 0);
const valveId = String(args.valveId ?? "").trim();

// 2) Prefix is required to build tag names
if (!prefix) {
  log("openValvePopup: prefix is empty");
  return;
}

// 3) Save selected valve context to internal vars
setVar("SelectedValvePrefix", prefix);
setVar("SelectedValveName", name || prefix);
setVar("SelectedValveIndex", index || 0);

// 4) Open popup and pass runtime args
openPopup("Popup_ValveControl", {
  title: "Valve Control: " + (name || prefix),
  tagPrefix: prefix,
  args: {
    valveId: valveId || prefix,
    valveName: name || prefix,
    valvePrefix: prefix,
    valveIndex: index || 0,
  },
});

// 1) Read popup runtime context
const ctx = getContext();
const params = (ctx && typeof ctx.parameters === "object" && ctx.parameters) ? ctx.parameters : {};

// 2) Resolve valve prefix from popup args/context
const paramPrefix = typeof params.valvePrefix === "string" ? params.valvePrefix.trim() : "";
const popupPrefix = typeof getCurrentTagPrefix() === "string" ? String(getCurrentTagPrefix()).trim() : "";
const prefix = paramPrefix || popupPrefix;

// 3) Prefix is required to control target valve
if (!prefix) {
  log("valveOpen: prefix is empty");
  return;
}

// 4) Send open command and update runtime feedback
await writeTag(prefix + ".OpenCmd", true);
await writeTag(prefix + ".CloseCmd", false);
await writeTag(prefix + ".Opened", true);
await writeTag(prefix + ".Closed", false);
await writeTag(prefix + ".State", 2);

